module RefModule(
	 clk,    
	 reset,  
	 input_pc,  
	 output_pc, 
	 PCWre   
);input wire[32-1:1-1] input_pc;
	 output reg[31:0] output_pc;
	 input clk, reset, PCWre;


	always@(posedge clk)begin
		if(reset == 0)begin  
			output_pc = 0;
		end
		else if(!PCWre)begin  
			output_pc = output_pc;
		end
		else if(PCWre)begin   
			output_pc = input_pc;
		end
	end

endmodule
